const items = $input.all();
const output = [];

for (const item of items) {
  let data = item.json;

  // Desenvolver body si n8n lo envuelve (común en webhooks)
  if (data.body !== undefined) {
    data = data.body;
  }

  const errors = [];
  // Campos reales de PublicacionInsigniaDTO (Consultor.publicarInsignia)
  const requiredFields = ["donanteId", "insigniaNombre", "imagenUrl", "fechaObtencion"];

  for (const field of requiredFields) {
    if (data[field] === undefined || data[field] === null) {
      errors.push(`Falta el campo '${field}'`);
    }
  }

  if (errors.length === 0) {
    if (typeof data["donanteId"] !== "number") {
      errors.push(`'donanteId' debe ser numérico (recibido: ${typeof data["donanteId"]})`);
    }
    if (typeof data["insigniaNombre"] !== "string" || data["insigniaNombre"].trim().length === 0) {
      errors.push(`'insigniaNombre' debe ser un string no vacío`);
    }
    if (typeof data["imagenUrl"] !== "string" || data["imagenUrl"].trim().length === 0) {
      errors.push(`'imagenUrl' debe ser un string no vacío`);
    }
    if (typeof data["fechaObtencion"] !== "string" || !/^\d{4}-\d{2}-\d{2}$/.test(data["fechaObtencion"])) {
      errors.push(`'fechaObtencion' debe ser un string con formato YYYY-MM-DD (recibido: ${JSON.stringify(data["fechaObtencion"])})`);
    }
    // donanteNombre es opcional (Donante.nombre es nullable en el backend)
    if (data["donanteNombre"] !== undefined && data["donanteNombre"] !== null && typeof data["donanteNombre"] !== "string") {
      errors.push(`'donanteNombre' debe ser un string si está presente`);
    }

    const allowedFields = ["donanteId", "donanteNombre", "insigniaNombre", "imagenUrl", "fechaObtencion"];
    const extraFields = Object.keys(data).filter(k => !allowedFields.includes(k));
    if (extraFields.length > 0) {
      errors.push(`Campos no permitidos: ${extraFields.join(", ")}`);
    }
  }

  if (errors.length > 0) {
    output.push({ json: { valid: false, error: errors.join("; "), data } });
  } else {
    output.push({ json: { valid: true, data } });
  }
}

return output;

const item = $input.first();
const { donanteId, donanteNombre, insigniaNombre, imagenUrl, fechaObtencion } = item.json.data;

// Si el backend todavía no conoce el nombre del donante, se muestra por id
const nombreMostrado = (donanteNombre && donanteNombre.trim().length > 0)
  ? donanteNombre
  : `Donante #${donanteId}`;

// Texto publicable. La imagen NO se genera acá: imagenUrl ya viene resuelta
// desde el dominio (Insignia.imagenUrl vía Consultor.publicarInsignia).
const postText = `🏅 ¡Felicitaciones, ${nombreMostrado}! \n\nAcabás de obtener la insignia "${insigniaNombre}" en DonaTrack. \n\n📅 Obtenida el ${fechaObtencion}\n\n¡Gracias por tu compromiso con quienes más lo necesitan! 💙 \n\n#DonaTrack #Donaciones #Solidaridad`;

return [{
  json: {
    donanteId,
    donanteNombre: nombreMostrado,
    insigniaNombre,
    imagenUrl,
    fechaObtencion,
    postText
  }
}];

const items = $input.all();

const lineas = items.map(item => {
  const d = item.json;
  const medalla = d.puesto === 1 ? "🥇" : d.puesto === 2 ? "🥈" : d.puesto === 3 ? "🥉" : `${d.puesto}.`;
  return `${medalla} Donante #${d.donanteId} - ${d.cantidadMisiones} misiones cumplidas`;
});

const mes = items.length > 0 ? items[0].json.mes : "";

const texto = `🏆 RANKING MENSUAL DE DONANTES\n\n${lineas.join("\n")}\n\n📅 Mes: ${mes}\n\nGracias a quienes hicieron posible ayudar este mes 💙`;

return [{ json: { texto, mes } }];
